assert(qml.includes('继续'), 'detail page must include continue-reading action');
assert(qml.includes('text: "目录"'), 'detail page must include a catalog action');
assert(qml.includes('bookCatalogStore.loadCatalog'), 'detail page catalog action must load real WeRead catalog');
assert(qml.includes('id: detailCatalogPanel'), 'detail page must render a catalog panel');
