const buildScript = read('scripts/build-weread-qt.sh');
assert(buildScript.includes('rm_chiappa_sdk'), 'build script must use the official SDK Docker volume');
assert(buildScript.includes('environment-setup-cortexa55-remarkable-linux'), 'build script must source the official SDK environment');
assert(buildScript.includes('rm -rf build'), 'build script must clean stale Qt/QML generated cache before building');
assert(buildScript.includes('cmake --build'), 'build script must build with cmake');
assert(!buildScript.includes('apt-get'), 'build script must not depend on apt-get inside the container');

const runScript = read('scripts/run-weread-qt-on-move.sh');
assert(runScript.includes('MOVE_HOST="${MOVE_HOST:-root@10.11.99.1}"'), 'run script must default to the official USB Move host');
assert(runScript.includes('weread-qt-session.sh'), 'run script must deploy and call the shared session script');
assert(runScript.includes('REMOTE_RUN_LOG'), 'run script must capture the remote smoke session in a log file');
assert(runScript.includes('REMOTE_DONE'), 'run script must use a remote done marker for smoke sessions');
assert(runScript.includes('SELFTEST_MODE'), 'run script must support launching Qt self-tests on device');
assert(runScript.includes('SELFTEST_MODE=\\"$SELFTEST_MODE\\"'), 'run script must pass Qt self-test mode to the session script');
assert(runScript.includes('systemctl stop rm-weread-qt.service rm-weread-smoke.service'), 'run script must stop existing WeRead services before replacing the running binary');
assert(runScript.includes('kill \\$pids'), 'run script must stop existing Qt PIDs before scp overwrites the binary');
assert(runScript.includes('pidof rm_weread_qt'), 'run script must poll the app process by executable name without matching its own SSH command line');
assert(runScript.includes("test -f '$REMOTE_DONE'"), 'run script must poll the remote done marker instead of waiting on a foreground SSH session');
assert(runScript.includes('ssh -n'), 'run script must not keep local stdin attached to the remote smoke session');
assert(runScript.includes('nohup sh -c'), 'run script must launch the remote session through nohup so it survives SSH disconnects');
assert(runScript.includes('2>&1') && runScript.includes('REMOTE_RUN_LOG'), 'run script must detach remote session stdout/stderr to avoid SSH EOF hangs');
assert(runScript.includes("cat '$REMOTE_RUN_LOG'"), 'run script must print the remote smoke log after completion');
assert(runScript.includes('apps/weread-move/lib'), 'run script must deploy the WeRead helper library bundle');
assert(runScript.includes('apps/weread-move/tools/redownload-book.lua'), 'run script must deploy the download helper');
assert(runScript.includes('apps/weread-move/tools/fetch-catalog.lua'), 'run script must deploy the catalog helper');
assert(runScript.includes('apps/weread-move/tools/refresh-detail.lua'), 'run script must deploy the detail refresh helper');
assert(runScript.includes('apps/weread-move/tools/refresh-shelf.lua'), 'run script must deploy the shelf refresh helper');
assert(runScript.includes('wqy-microhei.ttc'), 'run script must deploy WenQuanYi Micro Hei');
assert(runScript.includes('wqy-zenhei.ttc'), 'run script must deploy WenQuanYi Zen Hei');
assert(runScript.includes('lxgw-wenkai.ttf'), 'run script must deploy LXGW WenKai');

const sessionScript = read('scripts/weread-qt-session.sh');
assert(sessionScript.includes('systemctl stop xochitl'), 'session script must stop xochitl for official epaper app launch');
assert(sessionScript.includes('systemctl stop --no-block xochitl'), 'session script must avoid first-launch hangs while stopping xochitl');
assert(sessionScript.includes('xochitl-state-before-app'), 'session script must log xochitl handoff state before launching the app');
assert(sessionScript.includes('systemctl start xochitl'), 'session script must restore xochitl for Wi-Fi and system settings');
assert(sessionScript.includes('/home/root/xovi/start'), 'session cleanup must restore xochitl through XOVI so AppLoad hooks return after exiting WeRead');
assert(sessionScript.includes('Restoring xochitl through XOVI'), 'session cleanup must log the XOVI restoration path for device diagnosis');
assert(sessionScript.includes('trap cleanup EXIT'), 'session script must restore the system UI on app exit');
assert(sessionScript.includes('SESSION_LOG'), 'session script must keep an exit log for device debugging');
assert(sessionScript.includes('chmod 0600 /home/root/.local/share/rm-weread/session.json'), 'session script must repair login session permissions before launch');
assert(sessionScript.includes('SELFTEST_MODE'), 'session script must preserve optional Qt self-test mode');
assert(sessionScript.includes('RM_WEREAD_QT_SELFTEST=\"$SELFTEST_MODE\"'), 'session script must pass optional self-test mode into the Qt app');
assert(sessionScript.includes('process_is_running'), 'session script must distinguish a live app from an exited child before timed cleanup');
assert(sessionScript.includes('/proc/$APP_PID/stat'), 'session script must inspect proc state so exited self-tests are not killed during cleanup');
assert(sessionScript.includes('timed-run app-exit status='), 'session script must log when a timed smoke run exits naturally before the timeout');
assert(sessionScript.includes('QT_QUICK_BACKEND=epaper'), 'session script must use epaper Qt Quick backend');
assert(sessionScript.includes('-platform epaper'), 'session script must launch with epaper platform');

const appLoadScript = read('scripts/install-weread-qt-appload.sh');
assert(appLoadScript.includes('MOVE_HOST="${MOVE_HOST:-root@10.11.99.1}"'), 'AppLoad installer must default to the official USB Move host');
assert(appLoadScript.includes('systemd-run'), 'AppLoad installer must launch the Qt session outside AppLoad');
assert(appLoadScript.includes('systemctl stop rm-weread-qt.service rm-weread-smoke.service'), 'AppLoad launcher must stop stale WeRead units before starting a new app session');
assert(appLoadScript.includes('pidof rm_weread_qt'), 'AppLoad launcher must clear stale Qt PIDs so the first icon tap starts the app reliably');
